import anthropic
import json

client = anthropic.Anthropic()

def verify_faithfulness(source: str, summary: str) -> dict:
    """Check each claim in the summary against the source document."""
    response = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=512,
        system="""You are a fact-checking assistant.
For each claim in the summary, find the exact sentence(s) in the source that support it.
Output JSON:
{
  "claims": [
    {"claim": "<claim text>", "supported": true|false, "source_quote": "<exact quote or null>"}
  ],
  "overall_faithful": true|false
}""",
        messages=[
            {
                "role": "user",
                "content": f"Source:\n{source}\n\nSummary to verify:\n{summary}",
            }
        ],
    )
    return json.loads(response.content[0].text)

source = "The bridge reopened Monday after 14 months of repairs costing $3.2M. Officials said safety inspections passed."
summary = "The bridge reopened after repairs. The project took 14 months and cost $3.2 million. No injuries were reported during construction."

result = verify_faithfulness(source, summary)
for claim in result["claims"]:
    status = "✓" if claim["supported"] else "✗ HALLUCINATED"
    print(f"{status}: {claim['claim'][:60]}")
# ✓: The bridge reopened after repairs
# ✓: The project took 14 months and cost $3.2 million
# ✗ HALLUCINATED: No injuries were reported during construction
